action.content:
:root {
  --ink: #f8fbff;
  --ink-soft: #b7c7df;
  --ink-muted: #6f87a9;
  --surface: #071018;
  --surface-deep: #05080f;
  --surface-panel: rgba(7, 16, 24, 0.88);
  --surface-terminal: rgba(3, 7, 13, 0.95);
  --accent: #ff4655;
  --warm: #f6b35b;
  --cyan-soft: #7cf7ff;
  --safe: #64d48d;
  --border: rgba(246, 179, 91, 0.28);
  --border-strong: rgba(246, 179, 91, 0.55);
  --grid-line: rgba(124, 247, 255, 0.1);
  --mono: "JetBrains Mono", "SFMono-Regular", Consolas, monospace;
  --sans: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  --header-height: 68px;
  --radius: 2px;
  --shadow: 0 0 0 1px rgba(246, 179, 91, 0.08), 0 16px 48px rgba(0, 0, 0, 0.35);
  color: var(--ink);
  background: var(--surface-deep);
  font-family: var(--sans);
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  min-width: 320px;
  color: var(--ink);
  background:
    radial-gradient(circle at top, rgba(30, 68, 114, 0.35), transparent 28%),
    linear-gradient(180deg, #04070d 0%, #09111f 100%);
}

body::before {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  background-image:
    linear-gradient(rgba(255, 255, 255, 0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.02) 1px, transparent 1px);
  background-size: 32px 32px;
  mix-blend-mode: screen;
  opacity: 0.25;
}

a {
  color: inherit;
}

button,
a {
  min-height: 44px;
}

button:focus-visible,
a:focus-visible {
  outline: 2px solid var(--cyan-soft);
  outline-offset: 3px;
}

.ops-shell {
  min-height: 100vh;
  position: relative;
  overflow-x: hidden;
}

.ops-header {
  position: sticky;
  top: 0;
  z-index: 20;
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: 20px;
  min-height: var(--header-height);
  padding: 12px clamp(16px, 3vw, 32px);
  background: rgba(5, 8, 15, 0.86);
  border-bottom: 1px solid var(--border);
  backdrop-filter: blur(10px);
}

.brand-mark {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  font-family: var(--mono);
  font-size: 13px;
  letter-spacing: 0.22em;
  text-transform: uppercase;
}

.brand-badge {
  display: inline-grid;
  place-items: center;
  width: 38px;
  height: 38px;
  background: var(--accent);
  color: #16090a;
  font-weight: 800;
  letter-spacing: 0.08em;
  clip-path: polygon(10% 0, 100% 0, 100% 70%, 90% 100%, 0 100%, 0 30%);
}

.hud-nav {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 8px;
}

.hud-nav a {
  padding: 10px 14px;
  color: var(--ink-soft);
  text-decoration: none;
  text-transform: uppercase;
  letter-spacing: 0.16em;
  font-size: 12px;
  border: 1px solid transparent;
  background: rgba(255, 255, 255, 0.02);
  transition: border-color .2s ease, color .2s ease, background .2s ease;
}

.hud-nav a:hover,
.hud-nav a:focus-visible {
  color: var(--ink);
  border-color: var(--border-strong);
  background: rgba(246, 179, 91, 0.08);
}

.header-clock {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  font-family: var(--mono);
  font-size: 12px;
  letter-spacing: 0.16em;
  color: var(--warm);
  background: rgba(7, 16, 24, 0.9);
  border: 1px solid var(--border);
}

.hero-stage {
  position: relative;
  min-height: calc(100vh - var(--header-height));
  display: grid;
  align-items: end;
  padding: clamp(24px, 5vw, 48px);
  border-bottom: 1px solid var(--border);
  background:
    linear-gradient(90deg, rgba(5,8,15,.96) 0%, rgba(5,8,15,.7) 28%, rgba(5,8,15,.2) 52%, rgba(5,8,15,.88) 100%),
    linear-gradient(180deg, rgba(255,70,85,.14), transparent 26%),
    repeating-linear-gradient(90deg, transparent 0 80px, rgba(124,247,255,.08) 80px 81px),
    radial-gradient(circle at 78% 30%, rgba(255,70,85,.18), transparent 28%),
    linear-gradient(135deg, #08101b 0%, #0f1725 50%, #12090d 100%);
}

.scanlines::after {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: repeating-linear-gradient(180deg, rgba(255,255,255,.03) 0 2px, transparent 2px 5px);
  opacity: .22;
}

.stage-frame,
.stage-corner,
.stage-tag,
.tone-danger,
.tone-warn,
.tone-safe,
.kicker,
.cta-primary,
.cta-secondary,
.site-chip,
.round-node,
.terminal-chip {
  clip-path: polygon(8px 0, 100% 0, 100% calc(100% - 8px), calc(100% - 8px) 100%, 0 100%, 0 8px);
}

.stage-frame {
  position: absolute;
  inset: clamp(16px, 3vw, 32px);
  border: 1px solid rgba(124, 247, 255, 0.22);
}

.stage-corner {
  position: absolute;
  width: 96px;
  height: 64px;
  border: 1px solid var(--warm);
}

.stage-corner.tl { top: 0; left: 0; border-right: 0; border-bottom: 0; }
.stage-corner.tr { top: 0; right: 0; border-left: 0; border-bottom: 0; transform: scaleX(-1); }
.stage-corner.bl { bottom: 0; left: 0; border-right: 0; border-top: 0; transform: scaleY(-1); }
.stage-corner.br { bottom: 0; right: 0; border-left: 0; border-top: 0; transform: scale(-1); }

.stage-tag {
  position: absolute;
  padding: 10px 14px;
  background: rgba(7, 16, 24, 0.9);
  border: 1px solid var(--border-strong);
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.tag-top-left { top: clamp(20px, 4vw, 34px); left: clamp(20px, 4vw, 34px); color: var(--warm); }
.tag-top-right { top: clamp(20px, 4vw, 34px); right: clamp(20px, 4vw, 34px); color: var(--cyan-soft); }
.tag-bottom-left { bottom: clamp(20px, 4vw, 34px); left: clamp(20px, 4vw, 34px); color: var(--ink-soft); }
.tag-bottom-right { bottom: clamp(20px, 4vw, 34px); right: clamp(20px, 4vw, 34px); color: var(--safe); }

.stage-content {
  position: relative;
  z-index: 2;
  display: grid;
  grid-template-columns: minmax(0, 1.1fr) minmax(280px, .6fr);
  gap: 24px;
  max-width: 1440px;
  margin: 0 auto;
  width: 100%;
}

.kicker {
  display: inline-block;
  margin-bottom: 16px;
  padding: 8px 14px;
  background: var(--warm);
  color: #061018;
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: 0.22em;
  text-transform: uppercase;
}

.hero-title {
  margin: 0;
  font-size: clamp(2.3rem, 5vw, 4rem);
  line-height: 0.98;
  font-weight: 800;
  letter-spacing: 0.02em;
  text-transform: uppercase;
}

.hero-title .codename {
  display: block;
  color: var(--accent);
  font-family: var(--mono);
  font-size: clamp(1rem, 1.8vw, 1.25rem);
  letter-spacing: 0.4em;
  margin-bottom: 12px;
}

.hero-subtitle {
  max-width: 60ch;
  margin: 18px 0 0;
  font-size: 1.02rem;
  line-height: 1.8;
  color: var(--ink-soft);
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin-top: 28px;
}

.cta-primary,
.cta-secondary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  min-width: 180px;
  padding: 0 20px;
  min-height: 48px;
  border: 0;
  font-family: var(--mono);
  font-size: 12px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  text-decoration: none;
  cursor: pointer;
}

.cta-primary {
  background: var(--accent);
  color: #16090a;
}

.cta-secondary {
  background: transparent;
  color: var(--ink);
  border: 1px solid var(--border-strong);
}

.hero-meta {
  align-self: end;
  display: grid;
  gap: 10px;
  padding: 18px;
  background: var(--surface-panel);
  border: 1px solid var(--border);
  box-shadow: var(--shadow);
}

.meta-line {
  display: flex;
  justify-content: space-between;
  gap: 16px;
  padding-top: 10px;
  border-top: 1px solid rgba(124, 247, 255, 0.12);
  font-family: var(--mono);
  font-size: 12px;
  letter-spacing: 0.12em;
}

.meta-line:first-child { border-top: 0; padding-top: 0; }
.meta-label { color: var(--ink-muted); text-transform: uppercase; }
.meta-value { color: var(--ink); }

.section-shell {
  padding: clamp(48px, 8vw, 92px) clamp(16px, 3vw, 32px);
  border-bottom: 1px solid rgba(114, 190, 255, 0.1);
}

.section-inner {
  max-width: 1440px;
  margin: 0 auto;
}

.section-head {
  display: grid;
  gap: 12px;
  margin-bottom: 28px;
}

.section-kicker {
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: 0.24em;
  text-transform: uppercase;
  color: var(--warm);
}

.section-title {
  margin: 0;
  font-size: clamp(1.5rem, 3vw, 2.4rem);
  line-height: 1.05;
  text-transform: uppercase;
}

.section-note {
  margin: 0;
  max-width: 62ch;
  color: var(--ink-soft);
  line-height: 1.75;
}

.status-tape {
  display: grid;
  grid-template-columns: repeat(5, minmax(0, 1fr));
  gap: 1px;
  background: rgba(255,255,255,.06);
  border: 1px solid var(--border);
}

.tape-cell {
  display: grid;
  gap: 8px;
  padding: 18px;
  background: #071018;
}

.tape-label {
  color: var(--ink-muted);
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
}

.tape-value {
  font-family: var(--mono);
  font-size: 1.35rem;
  color: var(--ink);
}

.tone-danger { background: #ff4655; color: #16090a; padding: 4px 8px; display: inline-block; }
.tone-warn { background: #f6b35b; color: #16090a; padding: 4px 8px; display: inline-block; }
.tone-safe { background: #64d48d; color: #061018; padding: 4px 8px; display: inline-block; }

.editorial-flow {
  display: grid;
  grid-template-columns: 1.1fr .9fr;
  gap: 24px;
}

.phase-rail {
  display: grid;
  gap: 1px;
  background: rgba(255,255,255,.06);
  border: 1px solid var(--border);
}

.phase {
  display: grid;
  grid-template-columns: 120px 1fr;
  gap: 16px;
  padding: 20px;
  background: #071018;
}

.phase-code {
  font-family: var(--mono);
  color: var(--warm);
  font-size: 12px;
  letter-spacing: 0.2em;
}

.phase-title {
  margin: 0 0 8px;
  font-size: 1.25rem;
  text-transform: uppercase;
}

.phase-body {
  margin: 0;
  color: var(--ink-soft);
  line-height: 1.75;
}

.mark-row {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 14px;
}

.terminal-chip {
  display: inline-flex;
  align-items: center;
  padding: 7px 12px;
  background: rgba(246,179,91,.08);
  border: 1px solid var(--border);
  color: var(--ink);
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.rules-panel {
  display: grid;
  gap: 1px;
  background: rgba(255,255,255,.06);
  border: 1px solid var(--border);
}

.rule-row {
  display: grid;
  gap: 8px;
  padding: 18px;
  background: #071018;
}

.rule-row strong {
  color: var(--warm);
  font-family: var(--mono);
  font-size: 12px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
}

.rule-row p {
  margin: 0;
  color: var(--ink-soft);
  line-height: 1.7;
}

.loadout-table {
  width: 100%;
  border-collapse: collapse;
  background: #071018;
  border: 1px solid var(--border);
}

.loadout-table th,
.loadout-table td {
  padding: 14px 16px;
  text-align: left;
  vertical-align: top;
  border-bottom: 1px solid rgba(124,247,255,.1);
}

.loadout-table th {
  background: var(--warm);
  color: #16090a;
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
}

.loadout-table td {
  background: #071018;
  color: var(--ink);
}

.loadout-table .slot { color: var(--warm); font-family: var(--mono); font-size: 12px; letter-spacing: .16em; text-transform: uppercase; }
.loadout-table .note { color: var(--ink-muted); font-size: .92rem; }

.map-dashboard {
  display: grid;
  grid-template-columns: 1.1fr .9fr;
  gap: 24px;
}

.map-panel {
  position: relative;
  min-height: 420px;
  background:
    linear-gradient(rgba(124,247,255,.06) 1px, transparent 1px),
    linear-gradient(90deg, rgba(124,247,255,.06) 1px, transparent 1px),
    radial-gradient(circle at 30% 40%, rgba(255,70,85,.12), transparent 28%),
    linear-gradient(135deg, #08101b, #071018 55%, #12090d);
  background-size: 48px 48px, 48px 48px, auto, auto;
  border: 1px solid var(--border);
  overflow: hidden;
}

.map-overlay {
  position: absolute;
  inset: 24px;
}

.map-sites {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.site-chip {
  padding: 8px 14px;
  background: rgba(7,16,24,.9);
  border: 1px solid var(--border-strong);
  color: var(--ink);
  font-family: var(--mono);
  font-size: 12px;
  letter-spacing: .16em;
}

.route-line {
  position: absolute;
  height: 2px;
  background: currentColor;
  box-shadow: 0 0 16px currentColor;
}

.route-red { top: 28%; left: 8%; width: 52%; color: #ff4655; transform: rotate(-7deg); }
.route-amber { top: 52%; left: 14%; width: 58%; color: #f6b35b; transform: rotate(4deg); }
.route-slate { top: 70%; left: 18%; width: 54%; color: #7cf7ff; transform: rotate(-2deg); }

.map-marker {
  position: absolute;
  width: 44px;
  height: 44px;
  display: grid;
  place-items: center;
  background: #16090a;
  border: 1px solid var(--warm);
  color: var(--warm);
  font-family: var(--mono);
  font-weight: 700;
}

.marker-a { top: 22%; left: 52%; }
.marker-b { top: 48%; left: 68%; }
.marker-c { top: 66%; left: 38%; }

.map-readout {
  position: absolute;
  bottom: 18px;
  left: 18px;
  right: 18px;
  display: flex;
  justify-content: space-between;
  gap: 12px;
  padding: 12px 14px;
  background: rgba(3,7,13,.88);
  border: 1px solid var(--border);
  font-size: 12px;
  letter-spacing: .16em;
  color: var(--warm);
}

.route-switcher {
  display: grid;
  gap: 12px;
}

.route-button {
  width: 100%;
  padding: 16px;
  text-align: left;
  border: 1px solid var(--border);
  background: rgba(7,16,24,.82);
  color: var(--ink);
  cursor: pointer;
  display: grid;
  gap: 6px;
}

.route-button.active {
  border-color: var(--warm);
  box-shadow: inset 4px 0 0 var(--warm);
}

.route-button strong {
  font-family: var(--mono);
  font-size: 13px;
  letter-spacing: .2em;
  text-transform: uppercase;
}

.route-button span {
  color: var(--ink-muted);
  line-height: 1.6;
  font-size: .92rem;
}

.mono { font-family: var(--mono); }

.rounds-rail {
  display: grid;
  grid-template-columns: repeat(5, minmax(0, 1fr));
  gap: 1px;
  background: rgba(255,255,255,.06);
  border: 1px solid var(--border);
}

.round-node {
  padding: 20px;
  min-height: 220px;
  background: #071018;
  display: grid;
  gap: 12px;
  align-content: start;
  position: relative;
}

.round-node.active { background: linear-gradient(180deg, rgba(255,70,85,.18), #071018 45%); border-left: 0; }
.round-node .tick { font-family: var(--mono); color: var(--warm); letter-spacing: .2em; }
.round-node h3 { margin: 0; font-size: 1.1rem; text-transform: uppercase; }
.round-node p { margin: 0; color: var(--ink-soft); line-height: 1.7; }
.round-node .state { margin-top: auto; font-family: var(--mono); font-size: 11px; letter-spacing: .16em; color: var(--ink-muted); text-transform: uppercase; }

.stats-strip {
  display: grid;
  grid-template-columns: repeat(4, minmax(0,1fr));
  gap: 1px;
  margin-top: 24px;
  background: rgba(255,255,255,.06);
  border: 1px solid var(--border);
}

.stat-cell {
  padding: 22px 18px;
  background: #071018;
}

.stat-cell .value {
  display: block;
  font-family: var(--mono);
  font-size: 2rem;
  color: var(--warm);
}

.stat-cell .label {
  display: block;
  margin-top: 8px;
  color: var(--ink-muted);
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: .18em;
  text-transform: uppercase;
}

.footer {
  display: grid;
  grid-template-columns: 1.2fr repeat(2, .8fr);
  gap: 24px;
  padding: 28px;
  border-top: 1px solid rgba(114,190,255,.14);
  background: rgba(3,7,13,.95);
  color: #7b93b8;
  font-size: 13px;
}

.footer h4 {
  margin: 0 0 14px;
  color: var(--warm);
  font-family: var(--mono);
  font-size: 12px;
  letter-spacing: .2em;
  text-transform: uppercase;
}

.footer a {
  display: block;
  padding: 8px 0;
  text-decoration: none;
}

.email-input {
  width: 100%;
  min-height: 48px;
  padding: 0 14px;
  border: 1px solid var(--border);
  background: #071018;
  color: var(--ink);
  font-family: var(--mono);
}

.enroll-form {
  display: grid;
  gap: 10px;
  margin-top: 16px;
}

@media (max-width: 1100px) {
  .stage-content,
  .editorial-flow,
  .map-dashboard,
  .footer {
    grid-template-columns: 1fr;
  }
  .status-tape,
  .rounds-rail,
  .stats-strip {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 680px) {
  .ops-header,
  .status-tape,
  .rounds-rail,
  .stats-strip {
    grid-template-columns: 1fr;
  }
  .phase {
    grid-template-columns: 1fr;
    gap: 10px;
  }
  .stage-content {
    padding-top: 100px;
  }
  .hero-actions {
    flex-direction: column;
  }
  .cta-primary,
  .cta-secondary {
    width: 100%;
  }
  .loadout-table th,
  .loadout-table td {
    padding: 12px;
  }
}

@media (prefers-reduced-motion: reduce) {
  html { scroll-behavior: auto; }
  * { animation: none !important; transition: none !important; }
}
